import java.util.Arrays;

public int[] recoverArray(int n, int[] nums) {
    Arrays.sort(nums);
    int[] arr = new int[n];
    for (int i = 0; i < n; i++) {
        arr[i] = nums[i * 2];
    }
    return arr;
}
